DO $$
DECLARE
  u_admin    UUID := '0e276adf-8bb9-41af-95df-162ff4d5e2fd';
  u_user     UUID := 'da0ad867-f9e4-4d87-a710-05585f7238bb';
  u_mod      UUID := '4cc85430-01f1-4b08-9057-aa75994bc06a';
  u_legacy   UUID := 'd1f8c9a9-ad0e-4362-9a6e-1f0384fbf423';
  u_legacy_a UUID := 'ecc1e92d-b176-455b-b6e0-c1241ded3ce6';
  authors    UUID[];
  boards     TEXT[];
  titles     TEXT[];
  bodies     TEXT[];
  replies_   TEXT[];
  t_id       BIGINT;
  n_threads  INT := {opt.threads};
  max_rep    INT := {opt.replies};
  n_rep      INT;
  b_slug     TEXT;
  author     UUID;
  t_age      NUMERIC;
  new_id     BIGINT;
BEGIN
  authors  := ARRAY[u_admin, u_user, u_mod, u_legacy, u_legacy_a];
  boards   := ARRAY['general','announcements','support','feedback','off-topic'];
  titles   := ARRAY[
    'Has anyone tried the new approach yet?',
    'Quick tip that saved me hours this week',
    'Looking for advice on scaling this up',
    'Interesting benchmark results — thoughts?',
    'Deep dive: what actually happens under the hood',
    'Frustrated with the current workflow — ideas?',
    'Beginner question: where do I start?',
    'Show and tell: what I built this weekend',
    'Hot take: the conventional wisdom here is wrong',
    'Best resources you''ve found on this topic',
    'Breaking change in the latest release — heads up',
    'After 6 months I finally understand why this works',
    'Poll: how are you handling this in your setup?',
    'Solved: posting my fix in case it helps someone',
    'Weird edge case I hit — reproducible every time',
    'Compare and contrast: two approaches side by side',
    'The docs are misleading on this point',
    'Performance win: reduced load by 40%',
    'Feature request: please add this to the roadmap',
    'How do you test this kind of thing?',
    'Weekly check-in — what are you working on?',
    'Rant: why does this have to be so complicated?',
    'Collaboration wanted — anyone else tackling this?',
    'Configuration tip that nobody mentions',
    'Finally got this working after three days'
  ];
  bodies   := ARRAY[
    'I''ve been going back and forth on the best way to handle this and wanted to get a wider perspective from the community.',
    'Spent the morning reading through the source and found something counterintuitive that I thought was worth sharing.',
    'Background: we run this at around 50k req/min and started seeing tail latencies spike when we crossed a certain threshold.',
    'Happy to share the full config if anyone wants — took me a while to tune this to where I''m satisfied.',
    'First time posting here. Been lurking for a while and this community has already helped me enormously.',
    'TLDR at the bottom. Skip the backstory if you just want the fix.',
    'Putting together a comparison of the main options and would love input from people who have production experience.',
    'Just pushed a proof of concept. It''s rough, but it works, and the numbers surprised me.',
    'Disclaimer: I''m not an expert. Take this with appropriate skepticism and please correct me if I''m wrong.',
    'Reproducible every time on my machine. Steps to repro and full logs attached.'
  ];
  replies_ := ARRAY[
    'Thanks for posting this — been meaning to dig into it myself.',
    'This matched my experience exactly. Glad to know it''s not just me.',
    'Have you tried doing this with the alternative approach? Curious how they compare.',
    'Bookmarking this. Really useful reference.',
    'I hit the same issue last quarter. The root cause for us was slightly different but the fix is similar.',
    'Great write-up. One thing I''d add is to make sure you account for edge cases in the error path.',
    'How long have you been running this in production?',
    'We tried something similar and had mixed results. Happy to share our findings if useful.',
    'This deserves more attention — underrated thread.',
    'Could you expand on the part about configuration? That''s where I keep getting stuck.',
    '+1. Ran into this exact problem and your workaround is cleaner than what we ended up with.',
    'Marked as helpful. Will try this next week and report back.',
    'Slightly off-topic but related: did you also notice the performance difference on lower-spec machines?',
    'Genuinely surprised this isn''t in the official docs. Thanks for documenting it.',
    'One caveat worth mentioning — this approach breaks if you have more than a certain number of concurrent connections.',
    'Tested on my end. Confirmed working as described.',
    'Minor correction: in step 3 the parameter order is reversed. Everything else looks right.',
    'Has anyone benchmarked this against the naive approach? Wondering if the complexity is worth it.',
    'Following this thread. Will circle back once I''ve had a chance to test.',
    'This is the answer I was looking for. Simple, clear, and it works.'
  ];
  FOR i IN 1..n_threads LOOP
    b_slug  := boards[1 + ((i - 1) % array_length(boards, 1))];
    author  := authors[1 + ((i - 1) % array_length(authors, 1))];
    t_age   := (random() * 90)::NUMERIC;
    n_rep   := 50 + floor(random() * GREATEST(max_rep - 49, 1))::INT;
    INSERT INTO comments_v2 (
      target_type, target_id, author_id, title, body,
      depth, created_at, updated_at
    ) VALUES (
      'forum_board', b_slug, author,
      titles[1 + ((i - 1) % array_length(titles, 1))]
        || ' (#' || i || ')',
      bodies[1 + ((i - 1) % array_length(bodies, 1))],
      0,
      NOW() - (t_age || ' days')::INTERVAL,
      NOW() - (t_age || ' days')::INTERVAL
    ) RETURNING id INTO t_id;
    UPDATE comments_v2
      SET path = text2ltree(t_id::text)
      WHERE id = t_id;
    INSERT INTO comments_v2 (
      target_type, target_id, parent_id, author_id,
      body, depth, created_at, updated_at
    )
    SELECT
      'forum_thread', t_id::text, t_id,
      authors[1 + ((gs - 1) % array_length(authors, 1))],
      replies_[1 + ((gs - 1) % array_length(replies_, 1))],
      1,
      NOW() - ((t_age - gs * (t_age / (n_rep + 1))) || ' days')::INTERVAL,
      NOW() - ((t_age - gs * (t_age / (n_rep + 1))) || ' days')::INTERVAL
    FROM generate_series(1, n_rep) AS gs;
    UPDATE comments_v2
      SET path = text2ltree(t_id::text) || text2ltree(id::text)
      WHERE parent_id = t_id AND path IS NULL;
  END LOOP;
  RAISE NOTICE 'forum-seed: inserted % threads.', n_threads;
END $$;
